import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as l,e as i}from"./app-dec41dfb.js";const s={},e=i(`<h1 id="springcloud" tabindex="-1"><a class="header-anchor" href="#springcloud" aria-hidden="true">#</a> SpringCloud</h1><h2 id="_1-springcloud-对应的组件" tabindex="-1"><a class="header-anchor" href="#_1-springcloud-对应的组件" aria-hidden="true">#</a> 1. springcloud 对应的组件？</h2><ul><li>eureka <ul><li>注册中心</li></ul></li><li>ribbon <ul><li>负载均衡</li></ul></li><li>openfeign <ul><li>服务调用</li></ul></li><li>hystrix <ul><li>断路器</li></ul></li><li>zuul <ul><li>网关</li></ul></li><li>gateway <ul><li>新一代网关</li></ul></li><li>SpringCloud Config <ul><li>分布式配置中心</li></ul></li><li>SpringCloud Bus <ul><li>消息总线</li></ul></li><li>SpringCloud Stream <ul><li>消息驱动</li></ul></li><li>SpringCloud Sleuth <ul><li>分布式请求链路追踪</li></ul></li><li>SpringCloud Alibaba Nacos <ul><li>服务注册和配置中心</li></ul></li><li>SpringCloud Alibaba Sentinel <ul><li>服务的熔断和限流</li></ul></li><li>SpringCloud Alibaba Seata <ul><li>分布式事务</li></ul></li></ul><h2 id="_2-cap-base理论" tabindex="-1"><a class="header-anchor" href="#_2-cap-base理论" aria-hidden="true">#</a> 2. CAP&amp;BASE理论</h2><h3 id="_1-cap" tabindex="-1"><a class="header-anchor" href="#_1-cap" aria-hidden="true">#</a> 1. CAP</h3><ul><li><p>Consistency</p><ul><li>一致性</li><li>所有节点访问同一份最新的数据副本</li></ul></li><li><p>Availability</p><ul><li>可用性</li><li>非故障的节点在合理的时间内返回合理的响应</li></ul></li><li><p>Partition Tolerance</p><ul><li>分区容错性</li><li>分布式系统出现网络分区的时候，仍然能够对外提供服务</li></ul></li><li><p><strong>CAP 理论中分区容错性 P 是一定要满足的，在此基础上，只能满足可用性 A 或者一致性 C</strong></p></li><li><p>常见注册中心</p><ul><li>zookeeper保证的是cp <ul><li>任何时刻对 ZooKeeper 的读请求都能得到一致性的结果</li><li>zookeeper 不保证每次请求的可用性</li></ul></li><li>eureka保证的是ap <ul><li>Eureka 保证即使大部分节点挂掉也不会影响正常提供服务，只要有一个节点是可用的就行了</li></ul></li><li>nacos 支持ap和cp</li></ul></li></ul><h3 id="_2-base理论" tabindex="-1"><a class="header-anchor" href="#_2-base理论" aria-hidden="true">#</a> 2. BASE理论</h3><ul><li>Basically Available <ul><li>基本可用</li><li>分布式系统在出现不可预知故障的时候，允许损失部分可用性。但是，这绝不等价于系统不可用</li></ul></li><li>Soft-state <ul><li>软状态</li><li>允许系统中的数据存在中间状态（<strong>CAP 理论中的数据不一致</strong>），并认为该中间状态的存在不会影响系统的整体可用性，即允许系统在不同节点的数据副本之间进行数据同步的过程存在延时</li></ul></li><li>Eventually Consistent <ul><li>最终一致性</li><li>最终一致性强调的是系统中所有的数据副本，在经过一段时间的同步后，最终能够达到一个一致的状态</li></ul></li><li>核心思想 <ul><li>即使无法做到强一致性，但每个应用都可以根据自身业务特点，采用适当的方式来使系统达到最终一致性</li></ul></li></ul><h2 id="_3-springcloud-gateway" tabindex="-1"><a class="header-anchor" href="#_3-springcloud-gateway" aria-hidden="true">#</a> 3. SpringCloud Gateway</h2><h3 id="_1-spring-cloud-gateway-支持限流吗" tabindex="-1"><a class="header-anchor" href="#_1-spring-cloud-gateway-支持限流吗" aria-hidden="true">#</a> 1. spring cloud gateway 支持限流吗</h3><ul><li><p>支持，限流是一种常见的微服务网关功能，用于控制对后端服务的请求流量，以防止过载和保护后端服务</p></li><li><p>内置的限流过滤器是基于令牌桶算法或漏桶算法实现的</p><ul><li>令牌桶算法：允许一定的突发流量</li><li>漏桶算法则可以平滑请求流量</li></ul></li><li><p>实现</p><ul><li><p>方法一</p><ul><li><p>使用RequestRateLimiterGatewayFilterFactory来配置基于令牌桶算法的限流策略</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">spring</span><span class="token punctuation">:</span>
  <span class="token key atrule">cloud</span><span class="token punctuation">:</span>
    <span class="token key atrule">gateway</span><span class="token punctuation">:</span>
      <span class="token key atrule">routes</span><span class="token punctuation">:</span>
        <span class="token punctuation">-</span> <span class="token key atrule">id</span><span class="token punctuation">:</span> my_route
          <span class="token key atrule">uri</span><span class="token punctuation">:</span> http<span class="token punctuation">:</span>//example.org
          <span class="token key atrule">predicates</span><span class="token punctuation">:</span>
            <span class="token punctuation">-</span> Path=/foo/<span class="token important">**</span>
          <span class="token key atrule">filters</span><span class="token punctuation">:</span>
            <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> RequestRateLimiter
              <span class="token key atrule">args</span><span class="token punctuation">:</span>
                <span class="token key atrule">key-resolver</span><span class="token punctuation">:</span> <span class="token string">&quot;#{@userKeyResolver}&quot;</span>
                <span class="token key atrule">redis-rate-limiter.replenishRate</span><span class="token punctuation">:</span> <span class="token number">1</span>
                <span class="token key atrule">redis-rate-limiter.burstCapacity</span><span class="token punctuation">:</span> <span class="token number">3</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p>方法二</p><ul><li><p>自定义限流过滤器，实现GatewayFilter接口</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@Component</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">CustomRateLimiterFilter</span> <span class="token keyword">implements</span> <span class="token class-name">GatewayFilter</span><span class="token punctuation">,</span> <span class="token class-name">Ordered</span> <span class="token punctuation">{</span>
    <span class="token comment">// 实现限流逻辑</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li></ul></li></ul><h2 id="_4-分布式id" tabindex="-1"><a class="header-anchor" href="#_4-分布式id" aria-hidden="true">#</a> 4. 分布式ID</h2><h3 id="_1-雪花算法" tabindex="-1"><a class="header-anchor" href="#_1-雪花算法" aria-hidden="true">#</a> 1. 雪花算法</h3><p>雪花算法（Snowflake）是一种分布式唯一ID生成算法，它的实现原理是基于Twitter的Snowflake算法。Snowflake算法的核心思想是将一个64位的整数ID分成三部分：时间戳、机器ID和序列号。具体实现如下：</p><ol><li><p>时间戳部分（41位）：记录生成ID的时间，精确到毫秒级，可以用69年。</p></li><li><p>机器ID部分（10位）：记录机器的ID，可以分配1024台机器。</p></li><li><p>序列号部分（12位）：记录同一毫秒内生成的ID序号，可以生成4096个ID。</p></li></ol><p>Snowflake算法的优点包括：</p><ol><li><p>分布式唯一性：每个ID都是唯一的，且可以在分布式系统中生成。</p></li><li><p>高性能：生成ID的速度很快，不会影响系统的性能。</p></li><li><p>简单易用：Snowflake算法的实现比较简单，可以轻松集成到各种系统中。</p></li></ol><p>Snowflake算法的缺点包括：</p><ol><li><p>时钟回拨问题：如果系统时钟发生回拨，可能会导致生成的ID不唯一。</p></li><li><p>依赖机器ID：需要为每台机器分配一个唯一的ID，如果机器数量过多会增加管理成本。</p></li><li><p>有限的时间范围：由于时间戳部分只有41位，所以Snowflake算法能够使用的时间范围是有限的。</p></li></ol><p>总的来说，雪花算法是一种简单高效的分布式ID生成算法，适用于大多数分布式系统。但在实际应用中需要注意时钟回拨问题和机器ID的管理。</p><h3 id="_2-美团叶子算法" tabindex="-1"><a class="header-anchor" href="#_2-美团叶子算法" aria-hidden="true">#</a> 2. 美团叶子算法</h3><ul><li>leaf- 解决了雪花算法时钟回拨问题</li></ul><h2 id="_5-分布式锁" tabindex="-1"><a class="header-anchor" href="#_5-分布式锁" aria-hidden="true">#</a> 5. 分布式锁</h2><ul><li>redisson</li></ul><h2 id="_6-分布式事务" tabindex="-1"><a class="header-anchor" href="#_6-分布式事务" aria-hidden="true">#</a> 6. 分布式事务</h2><h3 id="_1-2pc-3pc-tcc了解么" tabindex="-1"><a class="header-anchor" href="#_1-2pc-3pc-tcc了解么" aria-hidden="true">#</a> 1. 2PC 3PC TCC了解么</h3><ul><li><p>2pc</p><ul><li><p>两阶段提交，将事务的提交过程分为资源准备和资源提交提交两个阶段，并且由事务协调者来协调所有事物参与者；如果准备阶段所有事物参与者都预留资源成功，则进行第二阶段的资源提交，否则事物协调者回滚资源</p></li><li><p>第一阶段：准备阶段</p></li><li><p>第二阶段：提交阶段</p><ul><li>事物的提交</li><li>事物的回滚</li></ul></li><li><p>缺点</p><ul><li>性能问题</li><li>可靠性问题</li><li>数据一致性问题</li><li>二阶段无法解决的问题 <ul><li>协调者在发出 commit 消息之后宕机，而唯一接收到这条消息的参与者同时也宕机了，那么即使协调者通过选举协议产生了新的协调者，这条事务的状态也是不确定的，没人知道事务是否被已经提交</li></ul></li></ul></li></ul></li><li><p>3pc</p><ul><li><p>三阶段提交协议</p></li><li><p>对2pc的改进，在第一阶段和第二阶段中插入了一个准备阶段</p></li><li><p>在协调者和参与者中引入超时机制</p></li><li><p>3pc会分为3个阶段</p><ul><li>准备阶段</li><li>预提交阶段 <ul><li>执行事务</li><li>或者中断事务</li></ul></li><li>提交阶段 <ul><li>提交事务</li><li>或者中断事务</li></ul></li></ul></li><li><p>优缺点</p><ul><li>优点 <ul><li>降低了阻塞范围，并且在等待超时后，协调者或参与者会中断事务，避免了协调者单点问题，</li></ul></li><li>缺点 <ul><li>数据不一致问题依然存在</li></ul></li></ul></li></ul></li><li><p>TCC</p><ul><li><p>全称：Try Confirm Cancel；是应用层的两阶段提交</p></li><li><p>核心思想</p><ul><li>针对每个操作，都要实现对应的确认和补偿操作，也就是业务逻辑的每个分支都需要实现try、confirm、cancel三个操作</li></ul></li><li><p>tcc的执行流程可以分为两个阶段</p><ul><li>第一阶段 <ul><li>try: 业务系统做检测并预留资源，比如常见的下单，在try阶段是将下单的库存给锁住</li></ul></li><li>第二阶段 <ul><li>根据第一阶段的结果决定是执行confirm还是cancel</li><li>cnonfirm : 执行真正的业务</li><li>cancle: 是对try阶段预留资源的释放（出问题，释放锁）</li></ul></li></ul></li></ul></li></ul><h2 id="_7-负载均衡" tabindex="-1"><a class="header-anchor" href="#_7-负载均衡" aria-hidden="true">#</a> 7. 负载均衡</h2><h3 id="_1-负载均衡算法" tabindex="-1"><a class="header-anchor" href="#_1-负载均衡算法" aria-hidden="true">#</a> 1. 负载均衡算法</h3><ul><li>随机法</li><li>轮询</li><li>加权轮询</li><li>加权随机</li><li>最小并发连接</li><li>哈希算法</li></ul><h2 id="_8-服务限流" tabindex="-1"><a class="header-anchor" href="#_8-服务限流" aria-hidden="true">#</a> 8. 服务限流</h2><h3 id="_1-常见限流算法" tabindex="-1"><a class="header-anchor" href="#_1-常见限流算法" aria-hidden="true">#</a> 1. 常见限流算法</h3><h4 id="_1-固定窗口计数器算法" tabindex="-1"><a class="header-anchor" href="#_1-固定窗口计数器算法" aria-hidden="true">#</a> 1. 固定窗口计数器算法</h4><ul><li>固定窗口其实就是时间窗口，固定窗口计数器算法规定了单位时间处理的请求数量</li><li>不推荐使用，体验差</li></ul><h4 id="_2-滑动窗口计数器算法" tabindex="-1"><a class="header-anchor" href="#_2-滑动窗口计数器算法" aria-hidden="true">#</a> 2. 滑动窗口计数器算法</h4><ul><li>是固定窗口计数器的升级版</li><li>它把时间以一定比例分配</li><li>当滑动窗口的格子划分的越多，滑动窗口的滚动就越平滑，限流的统计就会越精准</li></ul><h4 id="_3-漏桶算法" tabindex="-1"><a class="header-anchor" href="#_3-漏桶算法" aria-hidden="true">#</a> 3.漏桶算法</h4><ul><li>我们可以把发请求的动作比作成注水到桶中，我们处理请求的过程可以比喻为漏桶漏水。我们往桶中以任意速率流入水，以一定速率流出水。当水超过桶流量则丢弃，因为桶容量是不变的，保证了整体的速率</li><li>不推荐使用</li></ul><h4 id="_4-令牌桶算法" tabindex="-1"><a class="header-anchor" href="#_4-令牌桶算法" aria-hidden="true">#</a> 4. 令牌桶算法</h4><ol><li>基本原理： <ul><li>令牌桶算法维护一个固定容量的桶，桶中以固定速率生成令牌，每个令牌代表一个请求的处理权限。</li><li>当请求到达时，需要从桶中获取一个令牌，如果桶中有足够的令牌，则允许处理该请求；如果桶中没有足够的令牌，则拒绝该请求或者将请求放入队列中等待令牌。</li><li>桶中的令牌数量有上限，如果桶满了，新生成的令牌将被丢弃。</li></ul></li><li>实现限流的设计过程： <ul><li>初始化令牌桶，设置桶的容量和令牌生成速率。</li><li>定时以固定速率向桶中添加令牌，直到桶满为止。</li><li>当请求到达时，尝试从桶中获取一个令牌，如果成功则处理该请求，否则拒绝请求或者将请求放入队列中等待。</li></ul></li><li>不足之处： <ul><li>令牌桶算法对于突发流量的处理能力相对较弱，因为桶中的令牌数量有限，无法应对短时间内大量的请求。</li><li>令牌桶算法需要定时地生成令牌，这可能会引入额外的系统开销。</li></ul></li><li>更好的方案： <ul><li>漏桶算法：漏桶算法也是一种常用的限流算法，它通过固定速率的漏桶来控制请求的处理速度。与令牌桶算法相比，漏桶算法更适合对请求的突发流量进行限制。</li><li>基于漏桶算法的限流器可以更好地应对突发流量，并且可以通过动态调整漏桶的速率来适应不同的流量情况。</li></ul></li></ol><h2 id="_9-openfeigin" tabindex="-1"><a class="header-anchor" href="#_9-openfeigin" aria-hidden="true">#</a> 9 . openFeigin</h2><h3 id="_1-使用" tabindex="-1"><a class="header-anchor" href="#_1-使用" aria-hidden="true">#</a> 1. 使用</h3><ul><li>主启动类增加 @EnableFeiginClients</li><li>业务逻辑接口 @FeignClient</li></ul><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@Component</span>
<span class="token annotation punctuation">@FeignClient</span><span class="token punctuation">(</span>value <span class="token operator">=</span> <span class="token string">&quot;CLOUD-PAYMENT-SERVICE&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">interface</span> <span class="token class-name">PaymentFeignService</span>
<span class="token punctuation">{</span>
    <span class="token annotation punctuation">@GetMapping</span><span class="token punctuation">(</span>value <span class="token operator">=</span> <span class="token string">&quot;/payment/get/{id}&quot;</span><span class="token punctuation">)</span>
    <span class="token class-name">CommonResult</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Payment</span><span class="token punctuation">&gt;</span></span> <span class="token function">getPaymentById</span><span class="token punctuation">(</span><span class="token annotation punctuation">@PathVariable</span><span class="token punctuation">(</span><span class="token string">&quot;id&quot;</span><span class="token punctuation">)</span> <span class="token class-name">Long</span> id<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-超时时间" tabindex="-1"><a class="header-anchor" href="#_2-超时时间" aria-hidden="true">#</a> 2. 超时时间</h3><ul><li>openFeigin默认的超时时间是1秒钟。这意味着如果调用的服务在1秒内没有响应，openFeign将会抛出超时异常，需要修改配置</li></ul><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">feign</span><span class="token punctuation">:</span>
  <span class="token key atrule">client</span><span class="token punctuation">:</span>
    <span class="token key atrule">config</span><span class="token punctuation">:</span>
      <span class="token key atrule">default</span><span class="token punctuation">:</span>
       <span class="token comment">## 连接超时时间，设置了5秒</span>
        <span class="token key atrule">connectTimeout</span><span class="token punctuation">:</span> <span class="token number">5000</span>
        <span class="token comment">## 读取的超时时间，设置了10秒</span>
        <span class="token key atrule">readTimeout</span><span class="token punctuation">:</span> <span class="token number">10000</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_10-hystrix" tabindex="-1"><a class="header-anchor" href="#_10-hystrix" aria-hidden="true">#</a> 10 Hystrix</h2><h3 id="_1-服务降级" tabindex="-1"><a class="header-anchor" href="#_1-服务降级" aria-hidden="true">#</a> 1. 服务降级</h3><ul><li>定义 <ul><li>服务器忙，请稍后再试，不让客户端等待并立刻返回一个友好提示，fallback</li></ul></li><li>哪些情况会发生降级 <ul><li>程序运行异常</li><li>超时</li><li>服务熔断触发服务降级</li><li>线程池/信号量打满也会导致服务降级</li></ul></li></ul><h3 id="_2-服务熔断" tabindex="-1"><a class="header-anchor" href="#_2-服务熔断" aria-hidden="true">#</a> 2. 服务熔断</h3><ul><li><p>定义</p><ul><li><p>类似保险丝达到最大服务访问后，直接拒绝访问，拉闸限电，然后调用服务降级的方法并返回友好提示</p></li><li><p>服务的降级--&gt;进而熔断--&gt;恢复调用链路</p></li></ul></li></ul><h3 id="_3-服务限流" tabindex="-1"><a class="header-anchor" href="#_3-服务限流" aria-hidden="true">#</a> 3. 服务限流</h3><ul><li>定义 <ul><li>秒杀高并发等操作，严禁一窝蜂的过来拥挤，大家排队，一秒钟N个，有序进行</li></ul></li></ul><h3 id="_4-注解" tabindex="-1"><a class="header-anchor" href="#_4-注解" aria-hidden="true">#</a> 4. 注解</h3><h4 id="_1-hystrixcommand" tabindex="-1"><a class="header-anchor" href="#_1-hystrixcommand" aria-hidden="true">#</a> 1. @HystrixCommand</h4><ul><li>服务降级</li><li>需要有一个兜底的方法</li></ul><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@HystrixCommand</span><span class="token punctuation">(</span>fallbackMethod <span class="token operator">=</span> <span class="token string">&quot;paymentInfo_TimeOutHandler&quot;</span><span class="token punctuation">,</span>commandProperties <span class="token operator">=</span> <span class="token punctuation">{</span>
            <span class="token annotation punctuation">@HystrixProperty</span><span class="token punctuation">(</span>name<span class="token operator">=</span><span class="token string">&quot;execution.isolation.thread.timeoutInMilliseconds&quot;</span><span class="token punctuation">,</span>value<span class="token operator">=</span><span class="token string">&quot;3000&quot;</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">paymentInfo_TimeOut</span><span class="token punctuation">(</span><span class="token class-name">Integer</span> id<span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-defaultproperties-defaultfallback" tabindex="-1"><a class="header-anchor" href="#_2-defaultproperties-defaultfallback" aria-hidden="true">#</a> 2. @DefaultProperties(defaultFallback = &quot;&quot;)</h4><ul><li>@HystrixCommand 需要在每个方法配置一个，太繁琐</li></ul><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@DefaultProperties</span><span class="token punctuation">(</span>defaultFallback <span class="token operator">=</span> <span class="token string">&quot;payment_Global_FallbackMethod&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">PaymentHystirxController</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_11-sentinel" tabindex="-1"><a class="header-anchor" href="#_11-sentinel" aria-hidden="true">#</a> 11. sentinel</h2><h3 id="_1-sentinelresource" tabindex="-1"><a class="header-anchor" href="#_1-sentinelresource" aria-hidden="true">#</a> 1. @SentinelResource</h3><ul><li><p>可以对资源进行限流、熔断、降级等操作</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@SentinelResource</span><span class="token punctuation">(</span>value <span class="token operator">=</span> <span class="token string">&quot;resourceName&quot;</span><span class="token punctuation">,</span> blockHandler <span class="token operator">=</span> <span class="token string">&quot;handleBlock&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">getResource</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 方法逻辑</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在上面的例子中，<code>@SentinelResource</code> 注解标识了 <code>getResource</code> 方法为 Sentinel 的资源，其中 <code>value</code> 属性指定了资源的名称。另外，通过 <code>blockHandler</code> 属性指定了当资源被流控时的处理方法，即 <code>handleBlock</code> 方法。这样就可以实现对资源的限流操作。</p><p>除了 <code>blockHandler</code> 属性外，<code>@SentinelResource</code> 注解还支持其他属性，比如 <code>fallback</code>、<code>defaultFallback</code> 等，用于指定资源被降级或熔断时的处理方法</p></li></ul><h2 id="_12-seata" tabindex="-1"><a class="header-anchor" href="#_12-seata" aria-hidden="true">#</a> 12 . Seata</h2><h3 id="_1-使用-1" tabindex="-1"><a class="header-anchor" href="#_1-使用-1" aria-hidden="true">#</a> 1. 使用</h3><ul><li>@GlobalTransactional</li></ul><h3 id="_2-三大组件" tabindex="-1"><a class="header-anchor" href="#_2-三大组件" aria-hidden="true">#</a> 2. 三大组件</h3><ul><li><p>TC</p><ul><li>全局事务协调器，负责全局事务的协调和管理</li><li>Transaction Coordinator</li></ul></li><li><p>TM</p><ul><li>事务管理器，负责全局事务的发起、提交和回滚</li><li>Transaction Manager</li></ul></li><li><p>RM</p><ul><li>资源管理器，负责管理分支事务的生命周期</li><li>Resource Manager</li></ul></li><li><p>流程</p><ul><li>TM 开启分布式事务（TM 向 TC 注册全局事务记录）；</li><li>按业务场景，编排数据库、服务等事务内资源（RM 向 TC 汇报资源准备状态 ）；</li><li>TM 结束分布式事务，事务一阶段结束（TM 通知 TC 提交/回滚分布式事务）；</li><li>TC 汇总事务信息，决定分布式事务是提交还是回滚；</li><li>TC 通知所有 RM 提交/回滚 资源，事务二阶段结束。</li></ul></li></ul>`,69),t=[e];function p(u,c){return n(),l("div",null,t)}const d=a(s,[["render",p],["__file","springcloud.html.vue"]]);export{d as default};
